    39→function haversineKm(lat1: number, lon1: number, lat2: number, lon2: number): number {
    40→  const R = 6371;
    41→  const dLat = ((lat2 - lat1) * Math.PI) / 180;
    42→  const dLon = ((lon2 - lon1) * Math.PI) / 180;
    43→  const a =
    44→    Math.sin(dLat / 2) ** 2 +
    45→    Math.cos((lat1 * Math.PI) / 180) *
    46→      Math.cos((lat2 * Math.PI) / 180) *
    47→      Math.sin(dLon / 2) ** 2;
    48→  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    49→}
